var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그래서…….","JPN":"で……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"받은 돈으로 먹을 건 하나도 안 사고 이 데이터패드 쪼가리만 샀다고?","JPN":"貰った金で食べ物は何も買わずにこのデータパッドだけ買ったのか？","ENG":"You didn't buy food with the money, but you bought this tiny data pad piece of junk?","TWN":"你沒有把換到的錢拿去買吃的，而是買了這塊破爛板子嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그야 당연하죠! 여기에 묻혀 있는 것들은 분명 이것보다 훨씬 가치 있다고요!","JPN":"当り前です！　ここに埋まっているのはきっとこれより遥かに価値のあるものなんです！","ENG":"Of course! Everything that's buried there is worth so much more than this data pad!","TWN":"必須買吧！這張藏寶圖裡的寶藏一定更有價值！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"애초에 그게 진짜 대해적의 보물지도인지, 아니면 그냥 굴러다니던 장물에 있지도 않은 스토리를 가져다 붙인 건지 어떻게 확신해?","JPN":"そもそも、それが本当に大海賊の宝の地図なのか、ただ転がっていた贓物で嘘をついたのか、どうやってわかるんだ？","ENG":"How are you sure that it's really the Great Pirate's treasure map? What if he just told you a made-up story to sell some junk?","TWN":"你怎麼知道這真的是大海盜的藏寶圖，還是只是大家對贓物的以訛傳訛？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그야 의심할 필요도 없죠!","JPN":"それは疑う余地もありませんよ！","ENG":"Well, there's no doubt about it!","TWN":"完全不需要懷疑！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"수염 기르는 해적 출신 아저씨들은 거짓말 같은 거 안 하거든요!","JPN":"ヒゲのある元海賊のおじさんは嘘なんかしないんです！","ENG":"Ex-pirates with beards never lie!","TWN":"留鬍子的前任海盜大叔是不會說謊的！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"진짜 입 꾹 닫고 있는 것보다 신뢰도가 떨어지는 변명인데?","JPN":"黙っているより信頼できない答えなんだが？","ENG":"That's even worse than saying nothing.","TWN":"這句話完全沒有任何可信度。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"하아…","JPN":"はあ……","ENG":"*Sigh...*","TWN":"哀哀…"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그래도 남은 돈은 선장이 맡았으니, 이번에야 말로 제대로 된 음식을 사오겠지…","JPN":"でも残りの金は船長が持っているから、今度こそちゃんとした食べ物を買ってくるはず……","ENG":"At least the rest of the money is with Captain. She'll buy some proper food...","TWN":"至少剩下的錢在船長那裡，她應該會買些吃的回來吧…"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"샤크스 해적단! 좋은 소식이 있다!","JPN":"シャークス海賊団！　いい知らせがある！","ENG":"Hey, Sharks! I bring good news!","TWN":"大白鯊海盜團！有好消息！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"빈손인 걸 보니, 선장도 음식 안 사고 딴길로 샜구나?","JPN":"手ぶらなのを見ると、船長も食べ物を買わずに寄り道したな？","ENG":"Seeing as how you're empty-handed, I'm guessing you didn't buy food either.","TWN":"看船長兩手空空地回來，我想你也沒買吃的，而是買了其他東西吧？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬하핫, 역시 내 선원들은 눈치가 빠르다니까.","JPN":"キャハハッ、さすがあたしの船員は気が利くね。","ENG":"Kya hah hah, aren't you a witty one!","TWN":"哈哈哈，我的船員果然都很聰明。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"하아… 됐어.","JPN":"はあ……もういいよ。","ENG":"*Sigh...* Whatever.","TWN":"哀哀…算了。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그냥 먹을 건 내가 구해올 테니 돈이나 줘.","JPN":"食べ物はあたしが買ってくるから金をくれ。","ENG":"I'll get the food. Just give me the money.","TWN":"給我錢，我去買吃的東西回來吧。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"응? 한 푼도 안 남았는데?","JPN":"ん？　一つも残っていないけど？","ENG":"Hmm? I have no cash left.","TWN":"嗯？我全花光咧？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"뭐…?","JPN":"は……？","ENG":"What...?","TWN":"什麼…？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"선장, 대체 뭘 산 거야?","JPN":"船長、いったい何を買ったんだ？","ENG":"Captain, what on earth did you buy?","TWN":"船長，你到底買了什麼？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"쓸 만한 배를 하나 구했지. 커다란 대포도 달려 있지롱.","JPN":"使えそうな船を一つ手に入れた。大きい大砲も付いてるよ。","ENG":"I got us a ship. It's got a big cannon too.","TWN":"我買了一艘不錯的船，上面還有內建大砲呢。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그 돈을 전부 털어서 배를 샀다고?!","JPN":"その金を全部使って船を買ったって！？","ENG":"You used all that money to get a ship?!","TWN":"你把錢全拿去買船？！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"역시 선장! 돈 쓰는 법을 좀 아시네요!","JPN":"さすが船長！　お金の使い方をよくご存じですね！","ENG":"Ooh, Captain! That's what I'm talkin' about!","TWN":"不愧是船長！很懂得花錢！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"진심이야? 밥은 어쩌고? 우리 한 달 동안 고기도 못 먹었잖아?","JPN":"本気か？　ご飯はどうするの？　あたしたちお肉を１か月も食べてないよ？","ENG":"Are you serious? What about our meals? We haven't had any meat for a month.","TWN":"認真的嗎？那吃的呢？我們已經一個月都沒吃肉咧！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"게다가 헌터들이 눈에 불을 켜고 우릴 찾고 있을 텐데, 아직 현상금 문제도 해결 못했다고.","JPN":"しかもハンターは、やけになってあたしたちを探しているはずなのに、まだ懸賞金の問題も解決できていないんだ。","ENG":"Plus, the hunters are surely coming after us, but we haven't solved the bounty problem yet.","TWN":"現在獵人都在找我們，賞金的問題也還沒解決。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L35_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"흥, 평생 굶주리며 쫓기는 신세가 되더라도, 남의 배 빌려 타는 꼴사나운 해적이 될 순 없거든!","JPN":"ふん、一生腹ペコで追われる身になっても、他人の船を借りて乗る見苦しい海賊にはなれないんだ！","ENG":"Hmph. I can't be a disgraceful pirate that borrows others' ships! I'd rather starve and be chased my whole life!","TWN":"哼，我就算要一輩子餓肚子，也不要當一個跟別人借船的狼狽海盜！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그럼요! 선장님 체면에 육지를 떠돌다니, 그런 건 낭만이 아니죠!","JPN":"そうですよ！　船長なのに陸地を彷徨うなんて、そんなのはロマンではありません！","ENG":"Agreed! You're the captain! And the captain of the pirates never walks around on land!","TWN":"那當然！怎麼可以把船長的面子扔在地上，這樣一點都不浪漫！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"큭… 두 사람 정말…!","JPN":"くっ……二人とも、もう……！","ENG":"Kgh... You two just really...!","TWN":"呃…你們二個真的是…！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"아, 그리고.","JPN":"あ、それから。","ENG":"Oh, by the way.","TWN":"還有，"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"이거, 전 주인이 개조하기 전엔 고기잡이배로 썼었대. 그물 낚시도 할 수 있다더라.","JPN":"これ、前の主が改造する前は漁船として使っていたってさ。釣り用の網もあるらしい。","ENG":"Apparently, they used this as a fishing boat before the former owner modified it. Sounds like you can use fishing nets on this thing.","TWN":"這艘船的前任主人說，這艘船在改造前是魚船，可以撒網捕魚。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"난 육지 고기보단 소냐가 직접 해주는 생선구이가 더 좋은데 말이지.","JPN":"あたしは地の肉よりソーニャが作ってくれる魚焼きがいいんだよな。","ENG":"And I'd like Sonya's grilled fish rather than any meat above ground.","TWN":"而且比起陸地上的肉類，我更喜歡索妮雅親手烤的魚。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그물 없이도 낚시는 할 수 있어.","JPN":"網がなくても釣りはできる。","ENG":"I can fish, even without a net.","TWN":"沒有網子也可以捕魚。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그래서, 돈은 어떻게 다시 모을 작정이야?","JPN":"で、金はどうやってまた集めるつもりだ？","ENG":"So, how are we going to make money again?","TWN":"所以現在錢要怎麼來？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"미리 말해두지만 쫓기는 신세로 생선 장사는 못해.","JPN":"前もって言って置くけど追われている状態では魚商売はできないよ。","ENG":"I'll have you know that we can't sell fish while being chased.","TWN":"我先把話說清楚，我沒辦法一邊被追一邊賣魚。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그거라면 걱정 마셔.","JPN":"それなら心配するな。","ENG":"No worries.","TWN":"錢的事不用擔心。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"프론트베이의 바다에는 널린 게 돈주머니들이걸랑?","JPN":"フロントベイの海にはあちこちに金袋があるよ？","ENG":"The seas of Front Bay are full of lucrative opportunities!","TWN":"前灣海裡到處都是錢。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HUNTER_FRONTBAY_VETERAN_A","text":{"KOREA":"드디어 찾았다! 톱상어 재키!","JPN":"やっと見つけたぞ！　ノコギリザメ・ジャキ！","ENG":"Found you, Sawshark Jackie!","TWN":"終於找到了！杰克鯊鯊！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_VETERAN_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HUNTER_FRONTBAY_VETERAN_B","text":{"KOREA":"지긋지긋한 추격전도 이젠 끝이다!","JPN":"うんざりする追撃戦はもう終わりだ！","ENG":"This played-out chase ends here!","TWN":"無聊的追逐戰終於結束了！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_VETERAN_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_VETERAN_B","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HUNTER_FRONTBAY_VETERAN_A","text":{"KOREA":"카메라 준비됐지? 증거 영상이 없으면 현상금도 못 받는다고.","JPN":"カメラは用意したな？　証拠の動画がなければ懸賞金は貰えないんだ。","ENG":"Got the camera? We won't get the bounty if we don't have video evidence.","TWN":"相機準備好沒？要拍影片存證才能拿到賞金。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_VETERAN_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_VETERAN_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HUNTER_FRONTBAY_VETERAN_B","text":{"KOREA":"당연하지. 가자.","JPN":"当たたり前だ。行こう。","ENG":"Of course. Let's go.","TWN":"當然，走吧。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HUNTER_FRONTBAY_VETERAN_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HUNTER_FRONTBAY_VETERAN_B","face":"UNIT_IDLE"}}}}]`);export{e as default};